class Solution:
    def findPairs(self, nums: List[int], k: int) -> int:
        from collections import Counter
        cnt = Counter()
        ans = 0
        for x in nums:
            if k == 0:
                if cnt[x]:
                    ans += 1
            elif cnt[x - k]:
                ans += 1
            cnt[x] += 1
        return ans

